jQuery(document).ready(function(t){var e=t(".portfolio-container");e.imagesLoaded(function(){e.isotope({filter:"*",animationOptions:{duration:750,easing:"linear",queue:!1}})}),t(".portfolio-filter a").on("click",function(){t(".portfolio-filter .current").removeClass("current"),t(this).addClass("current");var i=t(this).attr("data-filter");return e.isotope({filter:i,animationOptions:{duration:750,easing:"linear",queue:!1}}),!1})});